type MemoryPackStore = {
	data: Map<string, unknown>;
	store: any;
};

function memoryPackStore(initial: Record<string, unknown> = {}): MemoryPackStore {
	const data = new Map<string, unknown>(Object.entries(initial));
	return {
		data,
		store: {
			async get(_packId: string, key: string) { return data.has(key) ? data.get(key) : null; },
			async put(_packId: string, key: string, value: unknown) { data.set(key, value); },
			async list(_packId: string, prefix = "") { return [...data.keys()].filter((key) => key.startsWith(prefix)).sort(); },
			async delete(_packId: string, key: string) { return data.delete(key); },
			async deletePrefix(_packId: string, prefix: string) {
				let count = 0;
				for (const key of [...data.keys()]) if (key.startsWith(prefix) && data.delete(key)) count++;
				return count;
			},
			async stats() { return { bytes: 0, keys: data.size }; },
			getSync(_packId: string, key: string) { return data.has(key) ? data.get(key) : null; },
		},
	};
}

async function postInternalBundleRead(stateDir: string, packStore: any, body: Record<string, unknown>): Promise<{ status: number; json: any }> {
	let status = 0;
	let text = "";
	const handled = await handlePrWalkthroughApiRoute(
		new URL("https://gateway.test/api/internal/pr-walkthrough/bundle"),
		{ method: "POST", headers: { "x-bobbit-session-secret": "secret-read" } } as any,
		{
			writeHead(code: number) { status = code; },
			end(chunk: unknown) { text = String(chunk ?? ""); },
		} as any,
		{
			defaultCwd: process.cwd(),
			stateDir,
			readBody: async () => body,
			packStore,
			sessionSecretStore: { resolveSessionIdBySecret: (secret: string | undefined) => secret === "secret-read" ? "child-session" : undefined } as any,
		},
	);
	assert.equal(handled, true);
	return { status, json: JSON.parse(text) };
}

